import React, { useState, useEffect } from 'react';
import { PieChart, Pie, Cell, LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';
import Sidebar from '../components/common/Sidebar';
import api from '../utils/api';

const COLORS = ['#ff6b6b','#ffc145','#00c9a7','#7c6cf0','#00d4c8','#d63031','#5ba4f5','#e17055'];

export default function DashboardPage() {
  const [s,setS]=useState(null);const [proj,setProj]=useState([]);const [ld,setLd]=useState(true);
  useEffect(()=>{Promise.all([api.get('/profile/stats').then(r=>setS(r.data)),api.get('/projects').then(r=>setProj(r.data))]).catch(()=>{}).finally(()=>setLd(false));},[]);

  if(ld)return<div className="app"><Sidebar projects={[]} chats={[]} onSelectProject={()=>{}} onSelectChat={()=>{}} onNewProject={()=>{}} onNewChat={()=>{}}/><div className="main"><div className="loading"><div className="spinner"/>Loading...</div></div></div>;

  const d=s?.errorDistribution||{};
  const pie=[{n:'Edge Case',v:d.edgeCaseMiss||0},{n:'Logic',v:d.logicError||0},{n:'Syntax',v:d.syntaxError||0},{n:'Optimization',v:d.optimizationMiss||0},{n:'Boundary',v:d.boundaryError||0},{n:'Off-by-One',v:d.offByOne||0},{n:'Wrong Approach',v:d.wrongApproach||0},{n:'Incomplete',v:d.incompleteSolution||0}].filter(x=>x.v>0);
  const acc=(s?.recentAccuracy||[]).map((h,i)=>({i:i+1,s:Math.round((h.score||0)*100)}));
  const heat=[];for(let i=0;i<28;i++){const v=(s?.totalAnalyses||0)>0?Math.random()*Math.min((s?.totalAnalyses||0)/5,1):0;heat.push({l:v>.7?3:v>.4?2:v>.1?1:0});}
  const hc=['var(--bg-tertiary)','var(--ok)','var(--warn)','var(--err)'];

  return(
    <div className="app">
      <Sidebar projects={proj} chats={[]} onSelectProject={()=>{}} onSelectChat={()=>{}} onNewProject={()=>{}} onNewChat={()=>{}}/>
      <div className="main"><div className="dash">
        <h2>🧠 Your Coding Mind</h2><p>Track thinking patterns and improve over time</p>
        <div className="dg">
          <div className="dc"><h3>Total Analyses</h3><div className="bn" style={{color:'var(--accent)'}}>{s?.totalAnalyses||0}</div><div className="subt">{s?.totalSuccessful||0} successful</div></div>
          <div className="dc"><h3>Success Rate</h3><div className="bn" style={{color:(s?.successRate||0)>50?'var(--ok)':'var(--warn)'}}>{s?.successRate||0}%</div></div>
          <div className="dc"><h3>🔥 Streak</h3><div className="bn" style={{color:'var(--accent2)'}}>{s?.currentStreak||0}</div><div className="subt">Longest: {s?.longestStreak||0}</div></div>
          <div className="dc"><h3>Top Error</h3><div className="bn" style={{color:'var(--err)',fontSize:pie.length?'1.1rem':'1.5rem'}}>{pie.length?pie.reduce((a,b)=>a.v>b.v?a:b).n:'—'}</div></div>
        </div>
        <div className="dg">
          <div className="dc"><h3>📊 Error Distribution</h3>{pie.length?<ResponsiveContainer width="100%" height={220}><PieChart><Pie data={pie} dataKey="v" nameKey="n" cx="50%" cy="50%" outerRadius={75} innerRadius={35} label={({n,percent})=>`${n} ${(percent*100).toFixed(0)}%`} labelLine={false} style={{fontSize:'.68rem'}}>{pie.map((_,i)=><Cell key={i} fill={COLORS[i%COLORS.length]}/>)}</Pie><Tooltip contentStyle={{background:'var(--bg-secondary)',border:'1px solid var(--border)',borderRadius:8,fontSize:'.8rem'}}/></PieChart></ResponsiveContainer>:<div className="empty" style={{height:200}}><p>Analyze code to see patterns</p></div>}</div>
          <div className="dc"><h3>📈 Accuracy Over Time</h3>{acc.length?<ResponsiveContainer width="100%" height={220}><LineChart data={acc}><XAxis dataKey="i" tick={{fontSize:10}} stroke="var(--border)"/><YAxis domain={[0,100]} tick={{fontSize:10}} stroke="var(--border)"/><Tooltip contentStyle={{background:'var(--bg-secondary)',border:'1px solid var(--border)',borderRadius:8}} formatter={v=>[`${v}%`,'Score']}/><Line type="monotone" dataKey="s" stroke="var(--accent)" strokeWidth={2} dot={{r:3}}/></LineChart></ResponsiveContainer>:<div className="empty" style={{height:200}}><p>Data appears after analyses</p></div>}</div>
        </div>
        <div className="dg">
          <div className="dc"><h3>🔥 Failure Heatmap (4 Weeks)</h3><div className="hm" style={{maxWidth:220}}>{heat.map((d,i)=><div key={i} className="hm-c" style={{background:hc[d.l]}}/>)}</div><div style={{display:'flex',gap:10,marginTop:8,fontSize:'.7rem',color:'var(--text-3)'}}><span>🟩 Few</span><span>🟨 Some</span><span>🟥 Many</span></div></div>
          <div className="dc"><h3>📌 Weak Topics</h3>{(s?.weakTopics||[]).length?<div style={{display:'flex',flexDirection:'column',gap:6}}>{s.weakTopics.map((t,i)=><div key={i} className="sug" style={{margin:0}}>⚠️ {t}</div>)}</div>:<div className="empty" style={{height:120}}><p>{(s?.totalAnalyses||0)>0?'Keep analyzing — patterns emerging':'Start analyzing to discover weak areas'}</p></div>}</div>
        </div>
        {(s?.patterns||[]).length>0&&<div className="dc"><h3>🔄 Recurring Patterns</h3><div style={{display:'flex',flexWrap:'wrap',gap:6}}>{s.patterns.map((p,i)=><span key={i} className="tag tag-w" style={{fontSize:'.78rem',padding:'4px 10px'}}>{p.pattern} <b>×{p.frequency}</b></span>)}</div></div>}
      </div></div>
    </div>
  );
}
